package tools

import (
	"fmt"
	"strings"
)

// Generator handles template-based code generation for Quill apps.
type AppGenerator struct {
	templates map[string]string // template name -> template content
}

// AppTemplate represents a generated application scaffold.
type AppTemplate struct {
	Name        string
	Description string
	Files       []GeneratedFile
}

// GeneratedFile represents a single generated file.
type GeneratedFile struct {
	Path    string
	Content string
}

// NewAppGenerator creates a new Generator with built-in templates.
func NewAppGenerator() *AppGenerator {
	return &AppGenerator{
		templates: make(map[string]string),
	}
}

// ParsePrompt extracts template type and parameters from natural language.
func ParsePrompt(prompt string) (string, string) {
	lower := strings.ToLower(prompt)

	// Check for CRUD pattern first: "crud <model>"
	if strings.Contains(lower, "crud") {
		// Extract model name
		parts := strings.Fields(lower)
		for i, p := range parts {
			if p == "crud" && i+1 < len(parts) {
				return "crud", parts[i+1]
			}
		}
		return "crud", "item"
	}

	// Match keywords to templates (ordered for deterministic matching)
	type templateMatch struct {
		name  string
		words []string
	}
	templates := []templateMatch{
		{"blog", []string{"blog", "post", "article", "writing"}},
		{"chat", []string{"chat", "realtime", "websocket", "messaging"}},
		{"dashboard", []string{"dashboard", "admin", "panel", "management"}},
		{"auth", []string{"auth", "login", "signup", "authentication", "session"}},
		{"api", []string{"api", "rest", "endpoint", "backend"}},
	}

	for _, tmpl := range templates {
		for _, word := range tmpl.words {
			if strings.Contains(lower, word) {
				return tmpl.name, ""
			}
		}
	}

	return "api", "" // default to API template
}

// Generate generates an app template based on the prompt.
func (g *AppGenerator) Generate(prompt string) AppTemplate {
	templateType, param := ParsePrompt(prompt)

	switch templateType {
	case "blog":
		return GenerateBlog()
	case "api":
		return GenerateAPI()
	case "chat":
		return GenerateChat()
	case "crud":
		return GenerateCRUD(param)
	case "auth":
		return GenerateAuth()
	case "dashboard":
		return GenerateDashboard()
	default:
		return GenerateAPI()
	}
}

// GenerateBlog generates a blog app scaffold.
func GenerateBlog() AppTemplate {
	return AppTemplate{
		Name:        "blog",
		Description: "A blog with auth, comments, and markdown support",
		Files: []GeneratedFile{
			{
				Path: "app.quill",
				Content: `-- Blog Application
-- Generated by Quill

server:
    port 3000

database:
    connect "sqlite://blog.db"

    model Post:
        title is string
        content is text
        author is string
        created_at is datetime

    model Comment:
        post_id is integer
        body is text
        author is string
        created_at is datetime

auth:
    secret "change-me-in-production"

    route post "/api/login":
        user is DB.find({email: request.body.email})
        token is Auth.createToken({id: user.id, email: user.email}, "change-me-in-production")
        respond {token: token}

route get "/api/posts":
    posts is DB._models.Post.find({})
    respond posts

route post "/api/posts":
    post is DB._models.Post.create(request.body)
    respond post status 201

route get "/api/posts/:id/comments":
    comments is DB._models.Comment.find({post_id: request.query.post_id})
    respond comments

route post "/api/posts/:id/comments":
    comment is DB._models.Comment.create(request.body)
    respond comment status 201
`,
			},
			{
				Path: "seeds/seed.quill",
				Content: `-- Seed data for blog
say "Seeding blog data..."

DB._models.Post.create({title: "Hello World", content: "Welcome to my blog!", author: "admin", created_at: "2024-01-01"})
DB._models.Post.create({title: "Second Post", content: "More content here.", author: "admin", created_at: "2024-01-02"})

say "Seeding complete!"
`,
			},
		},
	}
}

// GenerateAPI generates a REST API scaffold.
func GenerateAPI() AppTemplate {
	return AppTemplate{
		Name:        "api",
		Description: "A REST API with CRUD, auth middleware, and validation",
		Files: []GeneratedFile{
			{
				Path: "app.quill",
				Content: `-- REST API Application
-- Generated by Quill

server:
    port 3000

database:
    connect "sqlite://api.db"

    model Item:
        name is string
        description is text
        price is number
        created_at is datetime

auth:
    secret "change-me-in-production"

    route post "/api/login":
        token is Auth.createToken({role: "admin"}, "change-me-in-production")
        respond {token: token}

route get "/api/items":
    items is DB._models.Item.find({})
    respond items

route post "/api/items":
    item is DB._models.Item.create(request.body)
    respond item status 201

route get "/api/health":
    respond {status: "ok", uptime: process.uptime()}
`,
			},
		},
	}
}

