// GenerateCRUD generates CRUD routes and model definition for a given model name.
func GenerateCRUD(model string) AppTemplate {
	if model == "" {
		model = "item"
	}
	modelCap := strings.ToUpper(model[:1]) + model[1:]
	modelPlural := strings.ToLower(model) + "s"

	return AppTemplate{
		Name:        "crud-" + model,
		Description: fmt.Sprintf("CRUD routes for %s", modelCap),
		Files: []GeneratedFile{
			{
				Path: "app.quill",
				Content: fmt.Sprintf(`-- CRUD Application for %s
-- Generated by Quill

server:
    port 3000

database:
    connect "sqlite://app.db"

    model %s:
        name is string
        description is text
        created_at is datetime

route get "/api/%s":
    items is DB._models.%s.find({})
    respond items

route post "/api/%s":
    item is DB._models.%s.create(request.body)
    respond item status 201

route get "/api/%s/:id":
    item is DB._models.%s.findOne({id: request.query.id})
    respond item

route post "/api/%s/:id":
    result is DB._models.%s.update({id: request.query.id}, request.body)
    respond result

route post "/api/%s/:id/delete":
    result is DB._models.%s.delete({id: request.query.id})
    respond result
`, modelCap, modelCap,
					modelPlural, modelCap,
					modelPlural, modelCap,
					modelPlural, modelCap,
					modelPlural, modelCap,
					modelPlural, modelCap),
			},
		},
	}
}

// GenerateAuth generates authentication setup scaffold.
func GenerateAuth() AppTemplate {
	return AppTemplate{
		Name:        "auth",
		Description: "Login/signup/logout routes with JWT and session management",
		Files: []GeneratedFile{
			{
				Path: "app.quill",
				Content: `-- Auth Application
-- Generated by Quill

server:
    port 3000

database:
    connect "sqlite://auth.db"

    model User:
        email is string
        password is string
        name is string
        created_at is datetime

auth:
    secret "change-me-in-production"

    route post "/api/signup":
        user is DB._models.User.create(request.body)
        token is Auth.createToken({id: user.id, email: user.email}, "change-me-in-production")
        respond {user: user, token: token} status 201

    route post "/api/login":
        user is DB._models.User.findOne({email: request.body.email})
        token is Auth.createToken({id: user.id, email: user.email}, "change-me-in-production")
        respond {token: token}

    route get "/api/me":
        respond {message: "Protected route - implement token verification"}

route post "/api/logout":
    respond {message: "Logged out"}
`,
			},
		},
	}
}

